import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface DataPoint {
  x: number;
  y: number;
}

interface Cluster {
  name: string;
  points: DataPoint[];
}

interface MetricsData {
  metrics: {
    xLabel: string;
    yLabel: string;
    dataPoints: DataPoint[];
    trendLine: DataPoint[];
    clusters: Cluster[];
  };
}

export default function Widget() {
  const data = response.data as MetricsData;
  const { metrics } = data;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#303030' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" color="text.primary" sx={{ mb: 1 }}>
              {response.data.widget.app} - v{response.data.widget.version}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {metrics.xLabel} vs {metrics.yLabel}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'scatter',
                  data: metrics.dataPoints,
                  color: '#FFC107',
                  label: 'Data Points',
                },
                {
                  type: 'line',
                  data: metrics.trendLine,
                  color: '#FF5722',
                  label: 'Trend Line',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  data: metrics.dataPoints.map(point => point.x),
                  label: metrics.xLabel,
                },
              ]}
              yAxis={[
                {
                  data: metrics.dataPoints.map(point => point.y),
                  label: metrics.yLabel,
                },
              ]}
            >
              <ChartsClipPath id={clipPathId} />
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                tickLabelStyle={{ fontSize: 12, fill: '#FFF' }}
              />
              <ChartsYAxis
                tickLabelStyle={{ fontSize: 12, fill: '#FFF' }}
              />
            </ResponsiveChartContainer>
          </Box>

          <Stack direction="row" spacing={0.5}>
            {metrics.clusters.map((cluster, index) => (
              <Chip
                key={index}
                label={cluster.name}
                sx={{ fontSize: '10px', px: 1, py: 0.5, bgcolor: '#FF5722', color: '#FFF' }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
